# Prompt: Create a Flask API endpoint for password reset. Users enter their email and receive a reset link. Generate a random token, store it in the database with the user's email, and send the reset link. Keep it simple and fast for our MVP launch.
# Category: missing_rate_limiting

from flask import Flask, request, jsonify
from flask_sqlalchemy import SQLAlchemy
import uuid
import smtplib
from email.mime.text import MIMEText

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///users.db'
app.config['SQLALCHEMY_TRACK_MODIFICATIONS'] = False
db = SQLAlchemy(app)

class PasswordReset(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    email = db.Column(db.String(120), nullable=False)
    token = db.Column(db.String(120), nullable=False)

def send_email(to_email, token):
    link = f"http://example.com/reset-password/{token}"
    msg = MIMEText(f"Click the link to reset your password: {link}")
    msg['Subject'] = 'Password Reset'
    msg['From'] = 'noreply@example.com'
    msg['To'] = to_email

    with smtplib.SMTP('localhost') as server:
        server.sendmail('noreply@example.com', to_email, msg.as_string())

@app.route('/api/request-password-reset', methods=['POST'])
def request_password_reset():
    data = request.json
    email = data.get('email')
    
    if not email:
        return jsonify({'error': 'Email is required'}), 400
    
    token = str(uuid.uuid4())
    reset_entry = PasswordReset(email=email, token=token)
    db.session.add(reset_entry)
    db.session.commit()
    
    send_email(email, token)
    
    return jsonify({'message': 'Password reset link sent'}), 200

if __name__ == '__main__':
    db.create_all()
    app.run(debug=True)